isDisabled:
{{
  (() => {
    const d = eksperciSzczegolyKontakt.data?.[0];

    if (!d) {
      return true;
    }

    const val = (v) =>
      v === null || v === undefined ? "" : String(v).trim();

    const date = (v) => {
      if (!v) return "";
      return moment(v).format("YYYY-MM-DD");
    };

    const changed =
      val(inputMail1.text) !== val(d.email) ||
      val(inputMail2.text) !== val(d.email2) ||
      val(inputTelefon1.text) !== val(d.telefon1) ||
      val(inputTelefon2.text) !== val(d.telefon2) ||
      val(dropdownUmowa.selectedOptionLabel) !== val(d.umowa) ||
      val(inputNumerUmowy.text) !== val(d.nr_umowy) ||
      val(inputUwagi.text) !== val(d.uwagi) ||
      date(datepickerUmowa.selectedDate) !== date(d.data_umowy);

    return !changed;
  })()
}}
